Here's the XAML and ViewModel setup:

**XAML**

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="Auto,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1"
                           Text="{Binding Name}"
                           VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <ContentView>
                <Label Text="No items found."
                       HorizontalOptions="Center"
                       VerticalOptions="Center" />
            </ContentView>
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

**ViewModel**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool isRefreshing;

    [ObservableProperty]
    private Item? currentItem;

    public ObservableCollection<Item> Items { get; } = new();

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false; // Must set false to hide spinner
        }
    }

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (CurrentItem is null) return;

        await _nav.GoToAsync("DetailPage", new Dictionary<string, object>
        {
            { "Item", CurrentItem }
        });

        CurrentItem = null; // Reset so the same item can be re-selected
    }
}
```

**Key bindings explained:**

| Property | Purpose |
|---|---|
| `IsRefreshing` â†’ `TwoWay` | Controls the refresh spinner; set `false` when done |
| `RefreshCommand` | Fires on pull-down; reloads data from API |
| `SelectedItem` â†’ `TwoWay` | Tracks the currently selected item |
| `SelectionChangedCommand` | Fires on tap; navigates to detail page |
| `ItemsSource` â†’ `ObservableCollection<T>` | Required for automatic UI updates on add/remove |

**Important details:**
- Reset `CurrentItem = null` after navigation so the user can re-select the same item.
- Set `IsRefreshing = false` in a `finally` block to guarantee the spinner stops.
- Always update `Items` on the **UI thread** via `MainThread.BeginInvokeOnMainThread`.
- Use `x:DataType` on the `DataTemplate` for compiled bindings.
